import { test, expect, Page } from '@playwright/test';

/**
 * ShopFlow AI — Auto-Generated E2E Test Suite
 * Generated by : StoryForge AI Framework (Mistral 7B + Jinja2)
 * User Story   : US-001
 * Actor        : registered shopper on ShopFlow
 * Total Cases  : 3 E2E journey tests
 * Tool Stack   : Playwright + TypeScript
 * Target App   : https://shopflow.io
 */

const BASE_URL = 'https://shopflow.io';

// ── Shared helpers ────────────────────────────────────────────
async function login(page: Page) {
  await page.goto(`${BASE_URL}/login`);
  await page.locator('[data-testid="username-input"]').fill('johnsonjoshua');
  await page.locator('[data-testid="password-input"]').fill('Test@3218');
  await page.locator('[data-testid="login-btn"]').click();
  await expect(page).toHaveURL(/home|dashboard/);
}

/**
 * TC-E01 — [Positive] E2E Journey
 * Scenario : Full journey: login → search → add to cart → pay → order confirmed
 * AC       : AC1, AC2, AC4, AC7, AC8
 */
test('TC-E01: Full journey: login → search → add to cart → pay → order confirmed', async ({ page }) => {
  // ── Step 1: Login ─────────────────────────────────────────
  await login(page);

  // ── Step 2: Search for a product ──────────────────────────
  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();
  await expect(page.locator('[data-testid="product-card"]').first()).toBeVisible();

  // ── Step 3: Add to cart ───────────────────────────────────
  await page.locator('[data-testid="add-to-cart-btn"]').first().click();
  await expect(page.locator('[data-testid="cart-badge"]')).toBeVisible();

  // ── Step 4: Review cart ───────────────────────────────────
  await page.goto(`${BASE_URL}/cart`);
  await expect(page.locator('[data-testid="cart-item-name"]').first()).toBeVisible();
  await expect(page.locator('[data-testid="cart-total"]')).toBeVisible();
  await expect(page.locator('[data-testid="checkout-btn"]')).toBeEnabled();

  // ── Step 5: Enter payment details ─────────────────────────
  await page.locator('[data-testid="checkout-btn"]').click();
  await expect(page).toHaveURL(/checkout/);
  await page.locator('[data-testid="card-number"]').fill('4111111111111111');
  await page.locator('[data-testid="card-expiry"]').fill('12/28');
  await page.locator('[data-testid="card-cvv"]').fill('123');

  // ── Step 6: Place order ───────────────────────────────────
  await page.locator('[data-testid="pay-btn"]').click();

  // ── Step 7: Assert confirmation with unique order ID ──────
  await expect(page).toHaveURL(/confirmation/);
  await expect(page.locator('[data-testid="order-id"]')).toBeVisible();
  await expect(page.locator('[data-testid="order-status"]')).toHaveText('CONFIRMED');
  const orderId = await page.locator('[data-testid="order-id"]').textContent();
  expect(orderId).toBeTruthy();
  console.log(`✅ TC-E01: Order confirmed — ID: ${orderId}`);

});

/**
 * TC-E02 — [Negative] E2E Journey
 * Scenario : Invalid card shows payment error not 500
 * AC       : AC9
 */
test('TC-E02: Invalid card shows payment error not 500', async ({ page }) => {
  // ── E2E: Invalid payment card shows error not 500 ─────────
  await login(page);

  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();
  await page.locator('[data-testid="add-to-cart-btn"]').first().click();

  await page.goto(`${BASE_URL}/cart`);
  await page.locator('[data-testid="checkout-btn"]').click();

  // Enter invalid card details
  await page.locator('[data-testid="card-number"]').fill('0000000000000000');
  await page.locator('[data-testid="card-expiry"]').fill('01/20');
  await page.locator('[data-testid="card-cvv"]').fill('000');
  await page.locator('[data-testid="pay-btn"]').click();

  // Assert error message shown — NOT a 500
  await expect(page.locator('[data-testid="payment-error"]')).toBeVisible();
  await expect(page).not.toHaveURL(/confirmation/);
  const errorText = await page.locator('[data-testid="payment-error"]').textContent();
  expect(errorText).toBeTruthy();
  console.log(`✅ TC-E02: Payment error shown correctly — ${errorText}`);

});

/**
 * TC-E03 — [Edge] E2E Journey
 * Scenario : Session timeout redirects to login and cart is preserved
 * AC       : AC10
 */
test('TC-E03: Session timeout redirects to login and cart is preserved', async ({ page }) => {
  // ── E2E: Session timeout → redirect to login, cart preserved
  await login(page);

  // Add product to cart
  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();
  await page.locator('[data-testid="add-to-cart-btn"]').first().click();

  // Simulate session timeout by clearing auth token
  await page.evaluate(() => localStorage.removeItem('auth_token'));

  // Attempt checkout — should redirect to login
  await page.goto(`${BASE_URL}/checkout`);
  await expect(page).toHaveURL(/login/);

  // Re-login
  await page.locator('[data-testid="username-input"]').fill('johnsonjoshua');
  await page.locator('[data-testid="password-input"]').fill('Test@3218');
  await page.locator('[data-testid="login-btn"]').click();

  // Assert cart is preserved after re-login
  await page.goto(`${BASE_URL}/cart`);
  await expect(page.locator('[data-testid="cart-item-name"]').first()).toBeVisible();
  console.log('✅ TC-E03: Session timeout handled — cart preserved after re-login');
});

